from langchain.schema import BaseOutputParser
from typing import List, Dict, Any

class CitationParser(BaseOutputParser):
    def parse(self, text: str) -> Dict[str, Any]:
        # Extract citations from [1], [2] format
        import re
        citations = re.findall(r'\[[0-9]+\]', text)

        return {
            "answer": text,
            "citations": citations,
            "sources": self.retrieve_sources(citations)
        }

